\begin{aligned}
\log\left[
\frac{Pr(\mathbf{x},\mathbf{z}_{1\ldots T}|\phi_{1\ldots T})}
{q(\mathbf{z}_{1\ldots T}|\mathbf{x})}
\right]
&=
\log\left[
\frac{
Pr(\mathbf{x}|\mathbf{z}_{1},\phi_{1})
\prod_{t=2}^{T}Pr(\mathbf{z}_{t-1}|\mathbf{z}_{t},\phi_{t})
\cdot Pr(\mathbf{z}_{T})
}{
q(\mathbf{z}_{1}|\mathbf{x})
\prod_{t=2}^{T}q(\mathbf{z}_{t}|\mathbf{z}_{t-1})
}
\right] \\
&=
\log\left[
\frac{Pr(\mathbf{x}|\mathbf{z}_{1},\phi_{1})}
{q(\mathbf{z}_{1}|\mathbf{x})}
\right]
+\log\left[
\frac{
\prod_{t=2}^{T}Pr(\mathbf{z}_{t-1}|\mathbf{z}_{t},\phi_{t})
}{
\prod_{t=2}^{T}q(\mathbf{z}_{t}|\mathbf{z}_{t-1})
}
\right]
+\log\left[Pr(\mathbf{z}_{T})\right].
\end{aligned} \quad (18.22)
